#include <stdio.h>
#include <stdbool.h>

bool isValid(char *s) {
    int stack[10000];
    int top = -1;
    for (int i = 0; s[i]; i++) {
        if (s[i] == '(' || s[i] == '{' || s[i] == '[') {
            stack[++top] = s[i];
        } else {
            if (top == -1) return false;
            if ((s[i] == ')' && stack[top] == '(') ||
                (s[i] == '}' && stack[top] == '{') ||
                (s[i] == ']' && stack[top] == '[')) {
                top--;
            } else {
                return false;
            }
        }
    }
    return top == -1;
}

int main() {
    char s[] = "([{}])";
    printf("%d\n", isValid(s));
    return 0;
}

