class Solution {
    // Function to check if the input string has valid parentheses
    isValid(s) {
        let stack = [];  // Stack to store opening brackets

        for (let ch of s) {
            if (ch === '(' || ch === '{' || ch === '[') {
                stack.push(ch);  // Push opening brackets to stack
            } else {
                if (stack.length === 0) return false;  // No matching opening bracket
                let top = stack.pop();

                // Check for matching pair
                if ((ch === ')' && top === '(') ||
                    (ch === ']' && top === '[') ||
                    (ch === '}' && top === '{')) {
                    continue;
                } else {
                    return false;
                }
            }
        }

        return stack.length === 0;  // True if all brackets matched
    }
}

